export const dynamic = 'force-dynamic'

const ADMIN_HTML_B64 = ''

export async function GET() {
  const html = Buffer.from(ADMIN_HTML_B64, 'base64').toString('utf8')
  const secret = process.env.ADMIN_SECRET || ''
  const injection = `<script>try{sessionStorage.setItem('adminSecret',${JSON.stringify(secret)})}catch(e){}</script>`
  const patched = html.replace('</head>', injection + '</head>')
  return new Response(patched, {
    headers: {
      'Content-Type': 'text/html; charset=utf-8',
      'Cache-Control': 'no-store',
      'X-Robots-Tag': 'noindex, nofollow',
    },
  })
}